#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=55;
string s;
ll n,ans,c[N][N],cnt[N],a[N];
void init()
{
	c[0][0]=1;
	for(int i=1;i<=n;i++)
	{
		c[i][0]=c[i][i]=1;
		for(int j=1;j<i;j++)
		{
			c[i][j]=c[i-1][j]+c[i-1][j-1];
		}
	}
}
ll fun(int x)
{
//	cout<<x<<"::\n";
	ll sum=1;
	for(int i=0;i<=9;i++) 
	{
//		cout<<i<<" "<<x<<" "<<cnt[i]<<" "<<sum<<" ";
		sum*=c[x][cnt[i]];
//		cout<<sum<<"\n";
		x-=cnt[i];
	}
	return sum;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>s;
	n=s.size();
	s=" "+s;
	init();
	for(int i=1;i<=n;i++)
	{
		a[i]=s[i]-'0';
		cnt[a[i]]++;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<a[i];j++)
		{
			if(!cnt[j]) continue;
			cnt[j]--;
			ans+=fun(n-i);
			cnt[j]++;
		}
		cnt[a[i]]--;
	}
	cout<<ans;
	return 0;
}
